namespace sv_e97195400cda4ad7958038d5358c1660.Client.Auth;

/// <summary>
/// Serializable user info passed from server to WebAssembly via PersistentComponentState.
/// </summary>
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e97195400cda4ad7958038d5358c1660.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the persisted user info
/// written by the server during prerendering.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (!persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) ||
            userInfo is null)
        {
            _authState = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authState = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persisted"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e97195400cda4ad7958038d5358c1660.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded authenticated user.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state = Task.FromResult(CreateState());

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_e97195400cda4ad7958038d5358c1660.Client.Auth;

namespace sv_e97195400cda4ad7958038d5358c1660.Auth;

/// <summary>
/// Server-side provider that subscribes to the wrapped AuthenticationStateProvider and
/// persists the user info into PersistentComponentState so the WebAssembly client can
/// pick it up after the interactive runtime takes over.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _inner;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider inner)
    {
        _persistentState = persistentState;
        _inner = inner;

        AuthenticationStateChanged += _ => { };

        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    /// <inheritdoc />
    public event AuthenticationStateChangedHandler? AuthenticationStateChanged;

    /// <inheritdoc />
    public Task<AuthenticationState> GetAuthenticationStateAsync()
        => _inner.GetAuthenticationStateAsync();

    /// <inheritdoc />
    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
        AuthenticationStateChanged?.Invoke(authenticationStateTask);
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? _inner.GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value
                        ?? principal.Identity.Name
                        ?? string.Empty;

            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

